#nullable enable // autogenerated

using MVZ2.Vanilla.Entities;

using PVZEngine.Definitions;
using PVZEngine.Entities;

namespace MVZ2.GameContent.Projectiles
{
    [AutoEntityBehaviourDefinition(VanillaProjectileNames.explosiveSoul)]
    public class ExplosiveSoul : EntityBehaviourDefinition
    {
        public ExplosiveSoul(string nsp, string name) : base(nsp, name)
        {
        }
        public override void Update(Entity entity)
        {
            base.Update(entity);
            entity.Velocity += entity.GetFacingDirection();
        }
    }
}
